import subprocess

# Generate requirements.txt with hashes
subprocess.run(["pip", "freeze", "--all", "--local", "--out", "requirements.txt"])

# Generate Poetry lock file
subprocess.run(["poetry", "lock", "--no-dev"])

# Update requirements.txt with hashes
subprocess.run(["pip", "install", "-r", "requirements.txt", "--upgrade"])

# Update Poetry lock file
subprocess.run(["poetry", "update", "--lock"])

# Check for consistency between requirements.txt and Poetry lock file
subprocess.run(["diff", "requirements.txt", "poetry.lock"])